"use client";

import React, { useState } from "react";
import { CopilotKit, useLangGraphInterrupt } from "@copilotkit/react-core";
import {
  CopilotChat,
  useHumanInTheLoop,
  useConfigureSuggestions,
} from "@copilotkit/react-core/v2";
import { z } from "zod";

interface Step {
  description: string;
  status: "disabled" | "enabled" | "executing";
}

export default function HitlDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="human_in_the_loop">
      <DemoContent />
    </CopilotKit>
  );
}

function DemoContent() {
  useConfigureSuggestions({
    suggestions: [
      {
        title: "Simple plan",
        message: "Please plan a trip to mars in 5 steps.",
      },
      {
        title: "Complex plan",
        message: "Please plan a pasta dish in 10 steps.",
      },
    ],
    available: "always",
  });

  useLangGraphInterrupt({
    render: ({ event, resolve }) => (
      <StepSelector
        steps={event.value?.steps || []}
        onConfirm={(selectedSteps) => {
          resolve(
            "The user selected the following steps: " +
              selectedSteps.map((s) => s.description).join(", "),
          );
        }}
      />
    ),
  });

  useHumanInTheLoop({
    agentId: "human_in_the_loop",
    name: "generate_task_steps",
    description: "Generates a list of steps for the user to perform",
    parameters: z.object({
      steps: z.array(
        z.object({
          description: z.string(),
          status: z.enum(["enabled", "disabled", "executing"]),
        }),
      ),
    }),
    render: ({ args, respond, status }: any) => (
      <StepsFeedback args={args} respond={respond} status={status} />
    ),
  });

  return (
    <div className="flex justify-center items-center h-screen w-full">
      <div className="h-full w-full max-w-4xl">
        <CopilotChat
          agentId="human_in_the_loop"
          className="h-full rounded-2xl"
        />
      </div>
    </div>
  );
}

function StepSelector({
  steps,
  onConfirm,
}: {
  steps: Array<{ description?: string; status?: string } | string>;
  onConfirm: (steps: Step[]) => void;
}) {
  const [localSteps, setLocalSteps] = useState<Step[]>(() =>
    steps.map((s) => ({
      description: typeof s === "string" ? s : s.description || "",
      status: (typeof s === "object" && s.status === "disabled"
        ? "disabled"
        : "enabled") as Step["status"],
    })),
  );

  const enabledCount = localSteps.filter((s) => s.status === "enabled").length;

  return (
    <div
      className="rounded-xl border border-gray-200 bg-white p-6 shadow-lg w-[500px]"
      data-testid="select-steps"
    >
      <div className="mb-4 flex items-center justify-between">
        <h3 className="text-lg font-bold text-gray-800">Select Steps</h3>
        <span className="text-sm text-gray-500">
          {enabledCount}/{localSteps.length} selected
        </span>
      </div>
      <div className="space-y-2 mb-4">
        {localSteps.map((step, i) => (
          <label
            key={i}
            className="flex items-center gap-3 p-2 rounded-lg hover:bg-gray-50 cursor-pointer"
            data-testid="step-item"
          >
            <input
              type="checkbox"
              checked={step.status === "enabled"}
              onChange={() =>
                setLocalSteps((prev) =>
                  prev.map((s, j) =>
                    j === i
                      ? {
                          ...s,
                          status:
                            s.status === "enabled" ? "disabled" : "enabled",
                        }
                      : s,
                  ),
                )
              }
              className="w-4 h-4 rounded"
            />
            <span
              className={
                step.status !== "enabled"
                  ? "line-through text-gray-400"
                  : "text-gray-800"
              }
              data-testid="step-text"
            >
              {step.description}
            </span>
          </label>
        ))}
      </div>
      <button
        onClick={() =>
          onConfirm(localSteps.filter((s) => s.status === "enabled"))
        }
        className="w-full rounded-lg bg-purple-600 px-4 py-2 text-white font-medium hover:bg-purple-700"
      >
        Perform Steps ({enabledCount})
      </button>
    </div>
  );
}

function StepsFeedback({
  args,
  respond,
  status,
}: {
  args: any;
  respond: any;
  status: any;
}) {
  const [localSteps, setLocalSteps] = useState<Step[]>([]);
  const [decided, setDecided] = useState<boolean | null>(null);

  React.useEffect(() => {
    if (
      status === "executing" &&
      localSteps.length === 0 &&
      args?.steps?.length > 0
    ) {
      setLocalSteps(args.steps);
    }
  }, [status, args?.steps, localSteps.length]);

  if (!args?.steps?.length) return null;

  const steps = localSteps.length > 0 ? localSteps : args.steps;
  const enabledCount = steps.filter((s: any) => s.status === "enabled").length;

  return (
    <div
      className="rounded-xl border border-gray-200 bg-white p-6 shadow-lg w-[500px]"
      data-testid="select-steps"
    >
      <div className="mb-4 flex items-center justify-between">
        <h3 className="text-lg font-bold text-gray-800">Review Steps</h3>
        <span className="text-sm text-gray-500">
          {enabledCount}/{steps.length} selected
        </span>
      </div>
      <div className="space-y-2 mb-4">
        {steps.map((step: any, i: number) => (
          <label
            key={i}
            className="flex items-center gap-3 p-2 rounded-lg hover:bg-gray-50 cursor-pointer"
            data-testid="step-item"
          >
            <input
              type="checkbox"
              checked={step.status === "enabled"}
              disabled={status !== "executing"}
              onChange={() =>
                setLocalSteps((prev) =>
                  prev.map((s, j) =>
                    j === i
                      ? {
                          ...s,
                          status:
                            s.status === "enabled" ? "disabled" : "enabled",
                        }
                      : s,
                  ),
                )
              }
              className="w-4 h-4 rounded"
            />
            <span
              className={
                step.status !== "enabled"
                  ? "line-through text-gray-400"
                  : "text-gray-800"
              }
              data-testid="step-text"
            >
              {step.description}
            </span>
          </label>
        ))}
      </div>
      {decided === null && (
        <div className="flex gap-3">
          <button
            disabled={status !== "executing"}
            onClick={() => {
              setDecided(false);
              respond?.({ accepted: false });
            }}
            className="flex-1 rounded-lg border border-gray-300 px-4 py-2 font-medium hover:bg-gray-50 disabled:opacity-50"
          >
            Reject
          </button>
          <button
            disabled={status !== "executing"}
            onClick={() => {
              setDecided(true);
              respond?.({
                accepted: true,
                steps: localSteps.filter((s) => s.status === "enabled"),
              });
            }}
            className="flex-1 rounded-lg bg-green-600 px-4 py-2 text-white font-medium hover:bg-green-700 disabled:opacity-50"
          >
            Confirm ({enabledCount})
          </button>
        </div>
      )}
      {decided !== null && (
        <div
          className={`text-center py-2 rounded-lg font-medium ${decided ? "bg-green-50 text-green-700" : "bg-red-50 text-red-700"}`}
        >
          {decided ? "Accepted" : "Rejected"}
        </div>
      )}
    </div>
  );
}

"""Generic AG-UI runner for Claude Agent SDK demos.

Each cell's ``agent.py`` declares TOOLS / SYSTEM_PROMPT / AgentState / execute_tool
and optionally state_from_input / system_prompt_from_state, then calls
``make_runner(...)`` to get the ``run_agent`` coroutine mounted by agent_server.py.

The loop streams Claude responses as AG-UI events, executes tool calls on the
backend, and emits StateSnapshotEvent whenever a tool returns updated state.
"""

from __future__ import annotations

import json
import os
from collections.abc import AsyncIterator
from typing import Any, Callable

import anthropic
from ag_ui.core import (
    EventType,
    RunAgentInput,
    RunFinishedEvent,
    RunStartedEvent,
    StateSnapshotEvent,
    TextMessageContentEvent,
    TextMessageEndEvent,
    TextMessageStartEvent,
    ToolCallArgsEvent,
    ToolCallEndEvent,
    ToolCallResultEvent,
    ToolCallStartEvent,
)
from ag_ui.encoder import EventEncoder
from pydantic import BaseModel


def _extract_messages(input_data: RunAgentInput) -> list[dict[str, Any]]:
    out: list[dict[str, Any]] = []
    for msg in input_data.messages or []:
        role = msg.role.value if hasattr(msg.role, "value") else str(msg.role)
        if role not in ("user", "assistant"):
            continue
        content = ""
        if hasattr(msg, "content"):
            if isinstance(msg.content, str):
                content = msg.content
            elif isinstance(msg.content, list):
                parts: list[str] = []
                for part in msg.content:
                    if hasattr(part, "text"):
                        parts.append(part.text)
                    elif isinstance(part, dict) and "text" in part:
                        parts.append(part["text"])
                content = "".join(parts)
        if content:
            out.append({"role": role, "content": content})
    return out


def make_runner(
    *,
    tools: list[dict[str, Any]],
    system_prompt: str,
    state_cls: type[BaseModel],
    execute_tool: Callable[[str, dict[str, Any], BaseModel], tuple[str, BaseModel | None]],
    system_prompt_for_state: Callable[[str, BaseModel], str] | None = None,
) -> Callable[[RunAgentInput], AsyncIterator[str]]:
    """Build a ``run_agent`` coroutine suitable for the FastAPI wrapper."""

    async def run_agent(input_data: RunAgentInput) -> AsyncIterator[str]:
        encoder = EventEncoder()
        client = anthropic.AsyncAnthropic(api_key=os.getenv("ANTHROPIC_API_KEY", ""))

        state: BaseModel
        if input_data.state and isinstance(input_data.state, dict):
            try:
                state = state_cls(**input_data.state)
            except Exception:
                state = state_cls()
        else:
            state = state_cls()

        messages = _extract_messages(input_data)

        system = system_prompt
        if system_prompt_for_state is not None:
            system = system_prompt_for_state(system_prompt, state)

        thread_id = input_data.thread_id or "default"
        run_id = input_data.run_id or "run-1"

        yield encoder.encode(
            RunStartedEvent(
                type=EventType.RUN_STARTED, thread_id=thread_id, run_id=run_id
            )
        )

        while True:
            response_text = ""
            tool_calls: list[dict[str, Any]] = []
            msg_id = f"msg-{run_id}-{len(messages)}"

            yield encoder.encode(
                TextMessageStartEvent(
                    type=EventType.TEXT_MESSAGE_START,
                    message_id=msg_id,
                    role="assistant",
                )
            )

            async with client.messages.stream(
                model=os.getenv("ANTHROPIC_MODEL", "claude-opus-4-5"),
                max_tokens=4096,
                system=system,
                messages=messages,
                tools=tools,  # type: ignore[arg-type]
            ) as stream:
                current_tool_id: str | None = None
                current_tool_name: str | None = None
                current_tool_args = ""

                async for event in stream:
                    etype = type(event).__name__
                    if etype == "RawContentBlockStartEvent":
                        block = event.content_block  # type: ignore[attr-defined]
                        if block.type == "tool_use":
                            current_tool_id = block.id
                            current_tool_name = block.name
                            current_tool_args = ""
                            yield encoder.encode(
                                ToolCallStartEvent(
                                    type=EventType.TOOL_CALL_START,
                                    tool_call_id=current_tool_id,
                                    tool_call_name=current_tool_name,
                                    parent_message_id=msg_id,
                                )
                            )
                    elif etype == "RawContentBlockDeltaEvent":
                        delta = event.delta  # type: ignore[attr-defined]
                        if delta.type == "text_delta":
                            response_text += delta.text
                            yield encoder.encode(
                                TextMessageContentEvent(
                                    type=EventType.TEXT_MESSAGE_CONTENT,
                                    message_id=msg_id,
                                    delta=delta.text,
                                )
                            )
                        elif delta.type == "input_json_delta":
                            current_tool_args += delta.partial_json
                            yield encoder.encode(
                                ToolCallArgsEvent(
                                    type=EventType.TOOL_CALL_ARGS,
                                    tool_call_id=current_tool_id or "",
                                    delta=delta.partial_json,
                                )
                            )
                    elif etype == "RawContentBlockStopEvent":
                        if current_tool_id and current_tool_name:
                            yield encoder.encode(
                                ToolCallEndEvent(
                                    type=EventType.TOOL_CALL_END,
                                    tool_call_id=current_tool_id,
                                )
                            )
                            try:
                                parsed_args = (
                                    json.loads(current_tool_args)
                                    if current_tool_args
                                    else {}
                                )
                            except json.JSONDecodeError:
                                parsed_args = {}
                            tool_calls.append(
                                {
                                    "id": current_tool_id,
                                    "name": current_tool_name,
                                    "input": parsed_args,
                                }
                            )
                            current_tool_id = None
                            current_tool_name = None
                            current_tool_args = ""

            yield encoder.encode(
                TextMessageEndEvent(
                    type=EventType.TEXT_MESSAGE_END, message_id=msg_id
                )
            )

            if not tool_calls:
                break

            assistant_content: list[dict[str, Any]] = []
            if response_text:
                assistant_content.append({"type": "text", "text": response_text})
            for tc in tool_calls:
                assistant_content.append(
                    {
                        "type": "tool_use",
                        "id": tc["id"],
                        "name": tc["name"],
                        "input": tc["input"],
                    }
                )
            messages.append({"role": "assistant", "content": assistant_content})

            tool_results: list[dict[str, Any]] = []
            for tc in tool_calls:
                result_text, new_state = execute_tool(tc["name"], tc["input"], state)
                if new_state is not None:
                    state = new_state
                    if system_prompt_for_state is not None:
                        system = system_prompt_for_state(system_prompt, state)
                    yield encoder.encode(
                        StateSnapshotEvent(
                            type=EventType.STATE_SNAPSHOT,
                            snapshot=state.model_dump(),
                        )
                    )
                yield encoder.encode(
                    ToolCallResultEvent(
                        type=EventType.TOOL_CALL_RESULT,
                        tool_call_id=tc["id"],
                        content=result_text,
                    )
                )
                tool_results.append(
                    {
                        "type": "tool_result",
                        "tool_use_id": tc["id"],
                        "content": result_text,
                    }
                )
            messages.append({"role": "user", "content": tool_results})

        yield encoder.encode(
            RunFinishedEvent(
                type=EventType.RUN_FINISHED, thread_id=thread_id, run_id=run_id
            )
        )

    return run_agent

