        <CopilotSidebar
          defaultOpen={true}
          labels={{
            modalHeaderTitle: "AI Recipe Assistant",
          }}
        />
      </div>
    </CopilotKit>
  );
}

function Recipe() {
  const { agent } = useAgent({
    agentId: "shared-state-read",
    updates: [UseAgentUpdate.OnStateChanged, UseAgentUpdate.OnRunStatusChanged],
  });
  const { copilotkit } = useCopilotKit();

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Create Italian recipe",
        message: "Create a delicious Italian pasta recipe.",
      },
      {
        title: "Make it healthier",
        message: "Make the recipe healthier with more vegetables.",
      },
      {
        title: "Suggest variations",
        message: "Suggest some creative variations of this recipe.",
      },
    ],
    available: "always",
  });

  const agentState = agent.state as RecipeAgentState | undefined;
  const setAgentState = (s: RecipeAgentState) => agent.setState(s);
  const isLoading = agent.isRunning;

  useEffect(() => {
    if (!agentState?.recipe) {
      setAgentState(INITIAL_STATE);
    }
  }, []);

  const [recipe, setRecipe] = useState(INITIAL_STATE.recipe);
  const [editingInstructionIndex, setEditingInstructionIndex] = useState<
    number | null
  >(null);
  const changedKeysRef = useRef<string[]>([]);

  const updateRecipe = (partialRecipe: Partial<RecipeData>) => {
    setAgentState({
      ...(agentState || INITIAL_STATE),
      recipe: {
        ...recipe,
        ...partialRecipe,
      },
    });
    setRecipe({
      ...recipe,
      ...partialRecipe,
    });
  };

  // Sync agent state changes into local recipe state
  const newRecipeState = { ...recipe };
  const newChangedKeys: string[] = [];

  for (const key in recipe) {
    if (
      agentState?.recipe &&
      (agentState.recipe as any)[key] !== undefined &&
      (agentState.recipe as any)[key] !== null
    ) {
      let agentValue = (agentState.recipe as any)[key];
      const recipeValue = (recipe as any)[key];

      if (typeof agentValue === "string") {
        agentValue = agentValue.replace(/\\n/g, "\n");
      }

      if (JSON.stringify(agentValue) !== JSON.stringify(recipeValue)) {
        (newRecipeState as any)[key] = agentValue;
        newChangedKeys.push(key);
      }
    }
  }

  if (newChangedKeys.length > 0) {
    changedKeysRef.current = newChangedKeys;
  } else if (!isLoading) {
    changedKeysRef.current = [];
  }

  useEffect(() => {
    setRecipe(newRecipeState);
  }, [JSON.stringify(newRecipeState)]);

  const handleTitleChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    updateRecipe({ title: event.target.value });
  };

  const handleSkillLevelChange = (
    event: React.ChangeEvent<HTMLSelectElement>,
  ) => {
    updateRecipe({ skill_level: event.target.value as SkillLevel });
  };

  const handleDietaryChange = (preference: string, checked: boolean) => {
    if (checked) {
      updateRecipe({
        special_preferences: [...recipe.special_preferences, preference],
      });
    } else {
      updateRecipe({
        special_preferences: recipe.special_preferences.filter(
          (p) => p !== preference,
        ),
      });
    }
  };

  const handleCookingTimeChange = (
    event: React.ChangeEvent<HTMLSelectElement>,
  ) => {
    updateRecipe({
      cooking_time: cookingTimeValues[Number(event.target.value)].label,
    });
  };

  const addIngredient = () => {
    updateRecipe({
      ingredients: [
        ...recipe.ingredients,
        { icon: "🍴", name: "", amount: "" },
      ],
    });
  };

  const updateIngredient = (
    index: number,
    field: keyof Ingredient,
    value: string,
  ) => {
    const updatedIngredients = [...recipe.ingredients];
    updatedIngredients[index] = {
      ...updatedIngredients[index],
      [field]: value,
    };
    updateRecipe({ ingredients: updatedIngredients });
  };

  const removeIngredient = (index: number) => {
    const updatedIngredients = [...recipe.ingredients];
    updatedIngredients.splice(index, 1);
    updateRecipe({ ingredients: updatedIngredients });
  };

  const addInstruction = () => {
    const newIndex = recipe.instructions.length;
    updateRecipe({ instructions: [...recipe.instructions, ""] });
    setEditingInstructionIndex(newIndex);
  };

  const updateInstruction = (index: number, value: string) => {
    const updatedInstructions = [...recipe.instructions];
    updatedInstructions[index] = value;
    updateRecipe({ instructions: updatedInstructions });
  };

  const removeInstruction = (index: number) => {
    const updatedInstructions = [...recipe.instructions];
    updatedInstructions.splice(index, 1);
    updateRecipe({ instructions: updatedInstructions });
  };

  return (
    <form
      data-testid="recipe-card"
      className="max-w-2xl mx-auto p-6 bg-white rounded-2xl shadow-lg border border-gray-100"
    >
      {/* Recipe Title */}
      <div className="mb-6">
        <input
          type="text"
          value={recipe.title || ""}
          onChange={handleTitleChange}
          className="text-3xl font-bold w-full border-none outline-none bg-transparent"
        />

        <div className="flex gap-4 mt-3">
          <div className="flex items-center gap-1">
            <span>🕒</span>
            <select
              className="text-sm border rounded px-2 py-1"
              value={
                cookingTimeValues.find((t) => t.label === recipe.cooking_time)
                  ?.value || 3
              }
              onChange={handleCookingTimeChange}
            >
              {cookingTimeValues.map((time) => (
                <option key={time.value} value={time.value}>
                  {time.label}
                </option>
              ))}
            </select>
          </div>

          <div className="flex items-center gap-1">
            <span>🏆</span>
            <select
              className="text-sm border rounded px-2 py-1"
              value={recipe.skill_level}
              onChange={handleSkillLevelChange}
            >
              {Object.values(SkillLevel).map((level) => (
                <option key={level} value={level}>
                  {level}
                </option>
              ))}
            </select>
          </div>
        </div>
      </div>

      {/* Dietary Preferences */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("special_preferences") && <Ping />}
        <h2 className="text-lg font-semibold mb-2">Dietary Preferences</h2>
        <div className="flex flex-wrap gap-2">
          {Object.values(SpecialPreferences).map((option) => (
            <label
              key={option}
              className="flex items-center gap-1 text-sm bg-gray-50 px-3 py-1.5 rounded-full cursor-pointer hover:bg-gray-100"
            >
              <input
                type="checkbox"
                checked={recipe.special_preferences.includes(option)}
                onChange={(e) => handleDietaryChange(option, e.target.checked)}
              />
              <span>{option}</span>
            </label>
          ))}
        </div>
      </div>

      {/* Ingredients */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("ingredients") && <Ping />}
        <div className="flex items-center justify-between mb-2">
          <h2 className="text-lg font-semibold">Ingredients</h2>
          <button
            data-testid="add-ingredient-button"
            type="button"
            className="text-sm text-blue-600 hover:text-blue-800"
            onClick={addIngredient}
          >
            + Add Ingredient
          </button>
        </div>
        <div data-testid="ingredients-container" className="space-y-2">
          {recipe.ingredients.map((ingredient, index) => (
            <div
              key={index}
              data-testid="ingredient-card"
              className="flex items-center gap-3 p-3 bg-gray-50 rounded-lg"
            >
              <div className="text-2xl">{ingredient.icon || "🍴"}</div>
              <div className="flex-1 flex gap-2">
                <input
                  type="text"
                  value={ingredient.name || ""}
                  onChange={(e) =>
                    updateIngredient(index, "name", e.target.value)
                  }
                  placeholder="Ingredient name"
                  className="flex-1 text-sm border rounded px-2 py-1"
                />
                <input
                  type="text"
                  value={ingredient.amount || ""}
                  onChange={(e) =>
                    updateIngredient(index, "amount", e.target.value)
                  }
                  placeholder="Amount"
                  className="w-32 text-sm border rounded px-2 py-1"
                />
              </div>
              <button
                type="button"
                className="text-gray-400 hover:text-red-500 text-xl"
                onClick={() => removeIngredient(index)}
              >
                x
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Instructions */}
      <div className="mb-6 relative">
        {changedKeysRef.current.includes("instructions") && <Ping />}
        <div className="flex items-center justify-between mb-2">
          <h2 className="text-lg font-semibold">Instructions</h2>
          <button
            type="button"
            className="text-sm text-blue-600 hover:text-blue-800"
            onClick={addInstruction}
          >
            + Add Step
          </button>
        </div>
        <div data-testid="instructions-container" className="space-y-3">
          {recipe.instructions.map((instruction, index) => (
            <div key={index} className="flex items-start gap-3">
              <div className="flex-shrink-0 w-7 h-7 rounded-full bg-blue-500 text-white flex items-center justify-center text-sm font-bold">
                {index + 1}
              </div>
              <div
                className="flex-1 relative"
                onClick={() => setEditingInstructionIndex(index)}
              >
                <textarea
                  className="w-full text-sm border rounded px-3 py-2 resize-none"
                  value={instruction || ""}
                  onChange={(e) => updateInstruction(index, e.target.value)}
                  placeholder="Enter cooking instruction..."
                  onFocus={() => setEditingInstructionIndex(index)}
                  onBlur={() => setEditingInstructionIndex(null)}
                  rows={2}
                />
              </div>
              <button
                type="button"
                className="text-gray-400 hover:text-red-500 text-xl mt-1"
                onClick={() => removeInstruction(index)}
              >
                x
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Improve with AI Button */}
      <div className="flex justify-center">
        <button
          data-testid="improve-button"
          className={`px-6 py-3 rounded-xl font-semibold text-white transition-all ${
            isLoading
              ? "bg-gray-400 cursor-not-allowed"
              : "bg-gradient-to-r from-blue-500 to-purple-500 hover:from-blue-600 hover:to-purple-600 shadow-lg"
          }`}
          type="button"
          onClick={() => {
            if (!isLoading) {
              agent.addMessage({
                id: crypto.randomUUID(),
                role: "user",
                content: "Improve the recipe",
              });
              copilotkit.runAgent({ agent });
            }
          }}
          disabled={isLoading}
        >
          {isLoading ? "Please Wait..." : "Improve with AI"}
        </button>
      </div>
    </form>
  );
}

function Ping() {
  return (
    <span className="absolute -top-1 -right-1 flex h-3 w-3">
      <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75" />
      <span className="relative inline-flex rounded-full h-3 w-3 bg-blue-500" />
    </span>
  );
}

"""Generic AG-UI runner for Claude Agent SDK demos.

Each cell's ``agent.py`` declares TOOLS / SYSTEM_PROMPT / AgentState / execute_tool
and optionally state_from_input / system_prompt_from_state, then calls
``make_runner(...)`` to get the ``run_agent`` coroutine mounted by agent_server.py.

The loop streams Claude responses as AG-UI events, executes tool calls on the
backend, and emits StateSnapshotEvent whenever a tool returns updated state.
"""

from __future__ import annotations

import json
import os
from collections.abc import AsyncIterator
from typing import Any, Callable

import anthropic
from ag_ui.core import (
    EventType,
    RunAgentInput,
    RunFinishedEvent,
    RunStartedEvent,
    StateSnapshotEvent,
    TextMessageContentEvent,
    TextMessageEndEvent,
    TextMessageStartEvent,
    ToolCallArgsEvent,
    ToolCallEndEvent,
    ToolCallResultEvent,
    ToolCallStartEvent,
)
from ag_ui.encoder import EventEncoder
from pydantic import BaseModel


def _extract_messages(input_data: RunAgentInput) -> list[dict[str, Any]]:
    out: list[dict[str, Any]] = []
    for msg in input_data.messages or []:
        role = msg.role.value if hasattr(msg.role, "value") else str(msg.role)
        if role not in ("user", "assistant"):
            continue
        content = ""
        if hasattr(msg, "content"):
            if isinstance(msg.content, str):
                content = msg.content
            elif isinstance(msg.content, list):
                parts: list[str] = []
                for part in msg.content:
                    if hasattr(part, "text"):
                        parts.append(part.text)
                    elif isinstance(part, dict) and "text" in part:
                        parts.append(part["text"])
                content = "".join(parts)
        if content:
            out.append({"role": role, "content": content})
    return out


def make_runner(
    *,
    tools: list[dict[str, Any]],
    system_prompt: str,
    state_cls: type[BaseModel],
    execute_tool: Callable[[str, dict[str, Any], BaseModel], tuple[str, BaseModel | None]],
    system_prompt_for_state: Callable[[str, BaseModel], str] | None = None,
) -> Callable[[RunAgentInput], AsyncIterator[str]]:
    """Build a ``run_agent`` coroutine suitable for the FastAPI wrapper."""

    async def run_agent(input_data: RunAgentInput) -> AsyncIterator[str]:
        encoder = EventEncoder()
        client = anthropic.AsyncAnthropic(api_key=os.getenv("ANTHROPIC_API_KEY", ""))

        state: BaseModel
        if input_data.state and isinstance(input_data.state, dict):
            try:
                state = state_cls(**input_data.state)
            except Exception:
                state = state_cls()
        else:
            state = state_cls()

        messages = _extract_messages(input_data)

        system = system_prompt
        if system_prompt_for_state is not None:
            system = system_prompt_for_state(system_prompt, state)

        thread_id = input_data.thread_id or "default"
        run_id = input_data.run_id or "run-1"

        yield encoder.encode(
            RunStartedEvent(
                type=EventType.RUN_STARTED, thread_id=thread_id, run_id=run_id
            )
        )

        while True:
            response_text = ""
            tool_calls: list[dict[str, Any]] = []
            msg_id = f"msg-{run_id}-{len(messages)}"

            yield encoder.encode(
                TextMessageStartEvent(
                    type=EventType.TEXT_MESSAGE_START,
                    message_id=msg_id,
                    role="assistant",
                )
            )

            async with client.messages.stream(
                model=os.getenv("ANTHROPIC_MODEL", "claude-opus-4-5"),
                max_tokens=4096,
                system=system,
                messages=messages,
                tools=tools,  # type: ignore[arg-type]
            ) as stream:
                current_tool_id: str | None = None
                current_tool_name: str | None = None
                current_tool_args = ""

                async for event in stream:
                    etype = type(event).__name__
                    if etype == "RawContentBlockStartEvent":
                        block = event.content_block  # type: ignore[attr-defined]
                        if block.type == "tool_use":
                            current_tool_id = block.id
                            current_tool_name = block.name
                            current_tool_args = ""
                            yield encoder.encode(
                                ToolCallStartEvent(
                                    type=EventType.TOOL_CALL_START,
                                    tool_call_id=current_tool_id,
                                    tool_call_name=current_tool_name,
                                    parent_message_id=msg_id,
                                )
                            )
                    elif etype == "RawContentBlockDeltaEvent":
                        delta = event.delta  # type: ignore[attr-defined]
                        if delta.type == "text_delta":
                            response_text += delta.text
                            yield encoder.encode(
                                TextMessageContentEvent(
                                    type=EventType.TEXT_MESSAGE_CONTENT,
                                    message_id=msg_id,
                                    delta=delta.text,
                                )
                            )
                        elif delta.type == "input_json_delta":
                            current_tool_args += delta.partial_json
                            yield encoder.encode(
                                ToolCallArgsEvent(
                                    type=EventType.TOOL_CALL_ARGS,
                                    tool_call_id=current_tool_id or "",
                                    delta=delta.partial_json,
                                )
                            )
                    elif etype == "RawContentBlockStopEvent":
                        if current_tool_id and current_tool_name:
                            yield encoder.encode(
                                ToolCallEndEvent(
                                    type=EventType.TOOL_CALL_END,
                                    tool_call_id=current_tool_id,
                                )
                            )
                            try:
                                parsed_args = (
                                    json.loads(current_tool_args)
                                    if current_tool_args
                                    else {}
                                )
                            except json.JSONDecodeError:
                                parsed_args = {}
                            tool_calls.append(
                                {
                                    "id": current_tool_id,
                                    "name": current_tool_name,
                                    "input": parsed_args,
                                }
                            )
                            current_tool_id = None
                            current_tool_name = None
                            current_tool_args = ""

            yield encoder.encode(
                TextMessageEndEvent(
                    type=EventType.TEXT_MESSAGE_END, message_id=msg_id
                )
            )

            if not tool_calls:
                break

            assistant_content: list[dict[str, Any]] = []
            if response_text:
                assistant_content.append({"type": "text", "text": response_text})
            for tc in tool_calls:
                assistant_content.append(
                    {
                        "type": "tool_use",
                        "id": tc["id"],
                        "name": tc["name"],
                        "input": tc["input"],
                    }
                )
            messages.append({"role": "assistant", "content": assistant_content})

            tool_results: list[dict[str, Any]] = []
            for tc in tool_calls:
                result_text, new_state = execute_tool(tc["name"], tc["input"], state)
                if new_state is not None:
                    state = new_state
                    if system_prompt_for_state is not None:
                        system = system_prompt_for_state(system_prompt, state)
                    yield encoder.encode(
                        StateSnapshotEvent(
                            type=EventType.STATE_SNAPSHOT,
                            snapshot=state.model_dump(),
                        )
                    )
                yield encoder.encode(
                    ToolCallResultEvent(
                        type=EventType.TOOL_CALL_RESULT,
                        tool_call_id=tc["id"],
                        content=result_text,
                    )
                )
                tool_results.append(
                    {
                        "type": "tool_result",
                        "tool_use_id": tc["id"],
                        "content": result_text,
                    }
                )
            messages.append({"role": "user", "content": tool_results})

        yield encoder.encode(
            RunFinishedEvent(
                type=EventType.RUN_FINISHED, thread_id=thread_id, run_id=run_id
            )
        )

    return run_agent

import type { NextConfig } from "next";

const nextConfig: NextConfig = {
  // Allow iframe embedding from the showcase shell.
  async headers() {
