        "\n\nContext:\n" +
        input.context.map((c) => `${c.description}: ${c.value}`).join("\n");
    }

    const stream = await anthropic.messages.stream({
      model: CLAUDE_MODEL,
      max_tokens: 4096,
      system: systemPrompt,
      messages,
      stream: true,
      ...(tools.length > 0 ? { tools } : {}),
    });

    let toolCallId: string | null = null;
    let textStarted = false;

    for await (const ev of stream) {
      if (ev.type === "content_block_start") {
        if (ev.content_block.type === "tool_use") {
          toolCallId = ev.content_block.id;
          emit({
            type: EventType.TOOL_CALL_START,
            toolCallId,
            toolCallName: ev.content_block.name,
            parentMessageId: msgId,
          });
        }
      } else if (ev.type === "content_block_delta") {
        if (ev.delta.type === "text_delta") {
          if (!textStarted) {
            emit({
              type: EventType.TEXT_MESSAGE_START,
              messageId: msgId,
              role: "assistant",
            });
            textStarted = true;
          }
          emit({
            type: EventType.TEXT_MESSAGE_CONTENT,
            messageId: msgId,
            delta: ev.delta.text,
          });
        } else if (ev.delta.type === "input_json_delta" && toolCallId) {
          emit({
            type: EventType.TOOL_CALL_ARGS,
            toolCallId,
            delta: ev.delta.partial_json,
          });
        }
      } else if (ev.type === "content_block_stop") {
        if (toolCallId) {
          emit({ type: EventType.TOOL_CALL_END, toolCallId });
          toolCallId = null;
        }
      } else if (ev.type === "message_stop") {
        if (textStarted) {
          emit({ type: EventType.TEXT_MESSAGE_END, messageId: msgId });
        }
      }
    }

    emit({ type: EventType.RUN_FINISHED, runId, threadId });
  } catch (error: unknown) {
    const err = error as Error;
    console.error(`[agent] ERROR: ${err.message}`);
    try {
      emit({
        type: EventType.RUN_ERROR,
        runId,
        threadId,
        message: "An error occurred while processing the request",
        code: "AGENT_ERROR",
      });
    } catch {
      // client disconnected
    }
  }
  res.end();
});

