function Chat() {
  useFrontendTool({
    name: "get_weather",
    description: "Get the current weather for a given location.",
    parameters: z.object({
      location: z.string().describe("The city or location to check."),
    }),
    handler: async ({ location }: { location: string }) => {
      return {
        city: location,
        temperature: 68,
        humidity: 55,
        wind_speed: 10,
        conditions: "Sunny",
      };
    },
    render: ({ args, result, status }) => {
      const loading = status !== "complete";
      const parsed = (result ?? {}) as {
        city?: string;
        temperature?: number;
        humidity?: number;
        wind_speed?: number;
        conditions?: string;
      };

      return (
        <WeatherCard
          loading={loading}
          location={args?.location ?? parsed.city ?? ""}
          temperature={parsed.temperature}
          humidity={parsed.humidity}
          windSpeed={parsed.wind_speed}
          conditions={parsed.conditions}
        />
      );
    },
  });

  useConfigureSuggestions({
    suggestions: [
      {
        title: "Weather in SF",
        message: "What's the weather in San Francisco?",
      },
      {
        title: "Weather in Tokyo",
        message: "What's the weather in Tokyo?",
      },
    ],
    available: "always",
  });

  return (
    <CopilotChat
      agentId="tool-rendering-frontend-tools"
      className="h-full rounded-2xl"
    />
  );
}

"use client";

import React from "react";

export interface WeatherCardProps {
  loading: boolean;
  location: string;
  temperature?: number;
  humidity?: number;
  windSpeed?: number;
  conditions?: string;
}

export function WeatherCard({
  loading,
  location,
  temperature,
  humidity,
  windSpeed,
  conditions,
}: WeatherCardProps) {
  return (
    <div
      data-testid="weather-card"
      className="rounded-xl mt-4 mb-4 max-w-md w-full bg-gradient-to-br from-indigo-500 to-purple-600 text-white shadow-lg"
    >
      <div className="p-4">
        <div className="flex items-center justify-between">
          <div>
            <h3
              data-testid="weather-city"
              className="text-xl font-bold capitalize"
            >
              {location || "Weather"}
            </h3>
            <p className="text-white/80 text-sm">
              {loading ? "Fetching weather..." : "Current Weather"}
            </p>
          </div>
          <div className="text-4xl" aria-hidden>
            {loading ? "..." : conditionsEmoji(conditions)}
          </div>
        </div>

        {!loading && (
          <>
            <div className="mt-4 text-3xl font-bold">
              {temperature ?? "--"}&deg; F
              <span className="ml-2 text-sm font-normal capitalize text-white/80">
                {conditions}
              </span>
            </div>
            <div className="mt-4 pt-4 border-t border-white/30 grid grid-cols-2 gap-2 text-center text-sm">
              <div data-testid="weather-humidity">
                <p className="text-white/70 text-xs">Humidity</p>
                <p className="font-medium">{humidity ?? "--"}%</p>
              </div>
              <div data-testid="weather-wind">
                <p className="text-white/70 text-xs">Wind</p>
                <p className="font-medium">{windSpeed ?? "--"} mph</p>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

function conditionsEmoji(conditions?: string): string {
  if (!conditions) return "";
  const c = conditions.toLowerCase();
  if (c.includes("sun") || c.includes("clear")) return "sun";
  if (c.includes("rain") || c.includes("storm")) return "rain";
  if (c.includes("cloud")) return "cloud";
  if (c.includes("snow")) return "snow";
  return "";
}

