        name = data.get("name") or data.get("function", {}).get("name")
        args = data.get("arguments") or data.get("function", {}).get("arguments", {})
        if name:
            if isinstance(args, str):
                args = json.loads(args)
            for tool_cls in ALL_TOOLS:
