            if (i > 0) sb.append(",");
            sb.append(String.format("{\"category\":\"%s\",\"value\":%d,\"quarter\":\"Q1 2026\"}",
                categories.get(i), random.nextInt(90000) + 10000));
        }
        sb.append("]");
        return sb.toString();
    }
}

